import{r as t}from"./request-AtyKwpzJ.js";const s={getSeatPage(e){return t.get("/seat/page",{params:e})},getSeatTypes(){return t.get("/seat/types")},getAvailableSeats(e){return t.get("/seat/available",{params:e})},getSeatLayout(e){return t.get("/seat/layout",{params:e})},getSeatDetail(e){return t.get(`/seat/${e}`)},createSeat(e){return t.post("/seat/admin/create",e)},updateSeat(e,a){return t.put(`/seat/admin/${e}`,a)},deleteSeat(e){return t.delete(`/seat/admin/${e}`)},updateSeatStatus(e,a){return t.put(`/seat/admin/${e}/status`,null,{params:{status:a}})}};export{s};
